import React, { useState } from 'react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import './RevenueChart.css';

const data = [
  { name: 'Mon', revenue: 18400, expenses: 11200, profit: 7200 },
  { name: 'Tue', revenue: 22100, expenses: 13400, profit: 8700 },
  { name: 'Wed', revenue: 19800, expenses: 12100, profit: 7700 },
  { name: 'Thu', revenue: 31200, expenses: 15600, profit: 15600 },
  { name: 'Fri', revenue: 28900, expenses: 14300, profit: 14600 },
  { name: 'Sat', revenue: 35400, expenses: 16800, profit: 18600 },
  { name: 'Sun', revenue: 41200, expenses: 18900, profit: 22300 },
];

const CustomTooltip = ({ active, payload, label }) => {
  if (!active || !payload?.length) return null;
  return (
    <div className="chart-tooltip">
      <div className="tooltip-label">{label}</div>
      {payload.map(p => (
        <div key={p.name} className="tooltip-row">
          <span className="tooltip-dot" style={{ background: p.color }} />
          <span className="tooltip-name">{p.name}</span>
          <span className="tooltip-val">${(p.value / 1000).toFixed(1)}k</span>
        </div>
      ))}
    </div>
  );
};

export default function RevenueChart() {
  const [hovered, setHovered] = useState(null);
  return (
    <div className="card revenue-chart">
      <div className="chart-header">
        <div>
          <div className="card-title">Revenue Overview</div>
          <div className="chart-total">$197,000 <span className="chart-period">this week</span></div>
        </div>
        <div className="chart-legend">
          {[{ key: 'revenue', color: '#7c6af7', label: 'Revenue' }, { key: 'expenses', color: '#f97316', label: 'Expenses' }, { key: 'profit', color: '#22d3ee', label: 'Profit' }].map(l => (
            <div key={l.key} className={`legend-item ${hovered && hovered !== l.key ? 'dim' : ''}`} onMouseEnter={() => setHovered(l.key)} onMouseLeave={() => setHovered(null)}>
              <span className="legend-dot" style={{ background: l.color }} />
              {l.label}
            </div>
          ))}
        </div>
      </div>
      <ResponsiveContainer width="100%" height={220}>
        <AreaChart data={data} margin={{ top: 4, right: 4, left: -20, bottom: 0 }}>
          <defs>
            {[{ id: 'revenue', color: '#7c6af7' }, { id: 'expenses', color: '#f97316' }, { id: 'profit', color: '#22d3ee' }].map(g => (
              <linearGradient key={g.id} id={`grad-${g.id}`} x1="0" y1="0" x2="0" y2="1">
                <stop offset="0%" stopColor={g.color} stopOpacity={0.25} />
                <stop offset="100%" stopColor={g.color} stopOpacity={0} />
              </linearGradient>
            ))}
          </defs>
          <CartesianGrid stroke="rgba(255,255,255,0.04)" vertical={false} />
          <XAxis dataKey="name" tick={{ fill: 'rgba(240,240,245,0.35)', fontSize: 11 }} axisLine={false} tickLine={false} />
          <YAxis tick={{ fill: 'rgba(240,240,245,0.35)', fontSize: 11 }} axisLine={false} tickLine={false} tickFormatter={v => `$${v / 1000}k`} />
          <Tooltip content={<CustomTooltip />} />
          {[{ key: 'revenue', color: '#7c6af7' }, { key: 'expenses', color: '#f97316' }, { key: 'profit', color: '#22d3ee' }].map(s => (
            <Area key={s.key} type="monotone" dataKey={s.key} stroke={s.color} strokeWidth={2} fill={`url(#grad-${s.key})`} dot={false} activeDot={{ r: 4, strokeWidth: 0, fill: s.color }} opacity={hovered && hovered !== s.key ? 0.2 : 1} style={{ transition: 'opacity 0.2s' }} />
          ))}
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
}
